# --- Logging ---
sub audit_log {
    my ($level, $message) = @_;
    my $timestamp = localtime();
    my $log_entry = "[$timestamp] [$level] [PID:$$] $message\n";

    if (open(my $fh, '>>', $LOG_FILE)) {
        print $fh $log_entry;
        close($fh);
    }
    if ($level eq 'ERROR' || $level eq 'SECURITY') {
        warn $log_entry;
    }
}

# --- Load the integrity manifest (plugin_name => expected_sha256) ---
sub load_manifest {
    my ($manifest_path) = @_;
    my %manifest;

    unless (-f $manifest_path) {
        croak "Manifest file not found: $manifest_path";
    }

    # Verify manifest file permissions
    my @mstat = stat($manifest_path);
    unless (@mstat) {
        croak "Cannot stat manifest file: $!";
    }
    if ($mstat[4] != $TRUSTED_UID) {
        croak "Manifest file is not owned by trusted user (uid $TRUSTED_UID)";
    }
    if ($mstat[2] & S_IWOTH) {
        croak "Manifest file is world-writable — refusing to load";
    }

    open(my $fh, '<', $manifest_path)
        or croak "Cannot open manifest: $!";
    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/ || $line =~ /^\s*$/;
        if ($line =~ /^([a-f0-9]{64})\s+(\S+)$/) {
            $manifest{$2} = $1;
        } else {
            audit_log('ERROR', "Malformed manifest line: $line");
        }
    }
    close($fh);

    return \%manifest;
}

# --- Validate plugin filename (strict allowlist) ---
sub validate_plugin_name {
    my ($name) = @_;

    # Only allow simple alphanumeric names with underscores, ending in .pl
    unless (defined $name && $name =~ /\A[a-zA-Z][a-zA-Z0-9_]{0,63}\.pl\z/) {
        audit_log('SECURITY', "Invalid plugin name rejected: " . ($name // '<undef>'));
        return 0;
    }

    # Prevent path traversal
    if ($name =~ /\.\./ || $name =~ m{/} || $name =~ m{\\}) {
        audit_log('SECURITY', "Path traversal attempt in plugin name: $name");
        return 0;
    }

    return 1;
}

# --- Validate plugin file permissions and ownership ---
sub validate_plugin_file {
    my ($filepath) = @_;

    unless (-f $filepath) {
        audit_log('ERROR', "Plugin file does not exist: $filepath");
        return 0;
    }

    my @stat = stat($filepath);
    unless (@stat) {
        audit_log('ERROR', "Cannot stat plugin file $filepath: $!");
        return 0;
    }

    # Must be owned by trusted user
    if ($stat[4] != $TRUSTED_UID) {
        audit_log('SECURITY', "Plugin $filepath not owned by trusted uid $TRUSTED_UID (actual: $stat[4])");
        return 0;
    }

    # Must not be world-writable
    if ($stat[2] & S_IWOTH) {
        audit_log('SECURITY', "Plugin $filepath is world-writable");
        return 0;
    }

    # Must not be group-writable (defense in depth)
    if ($stat[2] & S_IWGRP) {
        audit_log('SECURITY', "Plugin $filepath is group-writable");
        return 0;
    }

    # Must not be a symlink
    if (-l $filepath) {
        audit_log('SECURITY', "Plugin $filepath is a symlink — rejected");
        return 0;
    }

    # Size check
    if ($stat[7] > $MAX_PLUGIN_SIZE) {
        audit_log('SECURITY', "Plugin $filepath exceeds max size ($stat[7] > $MAX_PLUGIN_SIZE)");
        return 0;
    }

    return 1;
}

# --- Verify plugin integrity against manifest ---
sub verify_integrity {
    my ($filepath, $plugin_name, $manifest) = @_;

    unless (exists $manifest->{$plugin_name}) {
        audit_log('SECURITY', "Plugin $plugin_name not found in manifest — unauthorized plugin");
        return 0;
    }

    open(my $fh, '<', $filepath)
        or do { audit_log('ERROR', "Cannot open $filepath for hashing: $!"); return 0; };
    local $/;
    my $content = <$fh>;
    close($fh);

    my $actual_hash = sha256_hex($content);
    my $expected_hash = $manifest->{$plugin_name};

    if ($actual_hash ne $expected_hash) {
        audit_log('SECURITY', "Integrity check FAILED for $plugin_name: expected=$expected_hash actual=$actual_hash");
        return 0;
    }

    audit_log('INFO', "Integrity check passed for $plugin_name");
    return 1;
}

