# --- Main plugin execution function ---
sub execute_plugin {
    my ($plugin_name) = @_;

    audit_log('INFO', "Plugin execution requested: $plugin_name");

    # Step 1: Validate plugin name
    unless (validate_plugin_name($plugin_name)) {
        audit_log('SECURITY', "Plugin name validation failed: $plugin_name");
        return { success => 0, error => 'Invalid plugin name' };
    }

    # Step 2: Construct and validate file path (canonicalize)
    my $plugin_path = File::Spec->catfile($PLUGIN_DIR, $plugin_name);
    my $canonical_path = File::Spec->canonpath($plugin_path);

    # Ensure the canonical path is still within PLUGIN_DIR
    my $canonical_dir = File::Spec->canonpath($PLUGIN_DIR);
    unless ($canonical_path =~ /^\Q$canonical_dir\E/) {
        audit_log('SECURITY', "Path traversal detected: $canonical_path not in $canonical_dir");
        return { success => 0, error => 'Path traversal detected' };
    }

    # Step 3: Validate file permissions and ownership
    unless (validate_plugin_file($canonical_path)) {
        return { success => 0, error => 'Plugin file validation failed' };
    }

    # Step 4: Load manifest and verify integrity
    my $manifest;
    eval {
        $manifest = load_manifest($MANIFEST_FILE);
    };
    if ($@) {
        audit_log('ERROR', "Failed to load manifest: $@");
        return { success => 0, error => 'Manifest loading failed' };
    }

    unless (verify_integrity($canonical_path, $plugin_name, $manifest)) {
        return { success => 0, error => 'Integrity verification failed' };
    }

    # Step 5: Read plugin code
    open(my $fh, '<', $canonical_path)
        or do {
            audit_log('ERROR', "Cannot open plugin $canonical_path: $!");
            return { success => 0, error => 'Cannot read plugin file' };
        };
    local $/;
    my $plugin_code = <$fh>;
    close($fh);

    # Step 6: Static analysis — check for dangerous patterns
    unless (validate_plugin_code($plugin_code, $plugin_name)) {
        return { success => 0, error => 'Plugin code contains forbidden operations' };
    }

    # Step 7: Execute in Safe compartment with timeout
    my $safe = create_safe_compartment();

    my $result;
    my $eval_error;

    # Set an alarm to prevent infinite loops
    local $SIG{ALRM} = sub { die "Plugin execution timeout\n" };
    alarm(5);  # 5-second timeout

    eval {
        $result = $safe->reval($plugin_code);
        $eval_error = $@ if $@;
    };

    my $outer_error = $@;
    alarm(0);  # Cancel alarm

    if ($outer_error) {
        audit_log('ERROR', "Plugin $plugin_name outer error: $outer_error");
        return { success => 0, error => "Plugin execution error: timeout or fatal" };
    }

    if ($eval_error) {
        # Sanitize error message before logging (don't leak internals)
        my $safe_error = $eval_error;
        $safe_error =~ s/[^\x20-\x7E]//g;
        $safe_error = substr($safe_error, 0, 256);
        audit_log('ERROR', "Plugin $plugin_name eval error: $safe_error");
        return { success => 0, error => "Plugin runtime error" };
    }

    audit_log('INFO', "Plugin $plugin_name executed successfully");
    return { success => 1, result => $result };
}

# --- Utility: Generate manifest entry for a plugin file ---
sub generate_manifest_entry {
    my ($plugin_name) = @_;

    unless (validate_plugin_name($plugin_name)) {
        die "Invalid plugin name\n";
    }

    my $filepath = File::Spec->catfile($PLUGIN_DIR, $plugin_name);
    unless (-f $filepath) {
        die "Plugin file not found: $filepath\n";
    }

    open(my $fh, '<', $filepath) or die "Cannot open $filepath: $!\n";
    local $/;
    my $content = <$fh>;
    close($fh);

    my $hash = sha256_hex($content);
    return "$hash  $plugin_name";
}

# --- Main entry point ---
sub main {
    # Verify plugin directory exists and has correct permissions
    unless (-d $PLUGIN_DIR) {
        die "Plugin directory does not exist: $PLUGIN_DIR\n";
    }

    my @dir_stat = stat($PLUGIN_DIR);
    if ($dir_stat[2] & S_IWOTH) {
        die "Plugin directory is world-writable — refusing to start\n";
    }

    # Process command-line arguments
    if (@ARGV == 0) {
        print "Usage:\n";
        print "  $0 run <plugin_name.pl>        - Execute a plugin\n";
        print "  $0 manifest <plugin_name.pl>    - Generate manifest entry\n";
        print "  $0 validate <plugin_name.pl>    - Validate a plugin without executing\n";
        exit 1;
    }

    my $command = $ARGV[0];

    if ($command eq 'run' && defined $ARGV[1]) {
        my $plugin_name = $ARGV[1];
        my $result = execute_plugin($plugin_name);

        if ($result->{success}) {
            print "Plugin executed successfully.\n";
            if (defined $result->{result}) {
                # Sanitize output
                my $output = "$result->{result}";
                $output =~ s/[^\x20-\x7E\n]//g;
                print "Result: $output\n";
            }
        } else {
            print "Plugin execution failed: $result->{error}\n";
            exit 1;
        }
    }
    elsif ($command eq 'manifest' && defined $ARGV[1]) {
        my $entry = generate_manifest_entry($ARGV[1]);
        print "$entry\n";
    }
    elsif ($command eq 'validate' && defined $ARGV[1]) {
        my $plugin_name = $ARGV[1];

        unless (validate_plugin_name($plugin_name)) {
            print "FAIL: Invalid plugin name\n";
            exit 1;
        }

        my $filepath = File::Spec->catfile($PLUGIN_DIR, $plugin_name);

        unless (validate_plugin_file($filepath)) {
            print "FAIL: File permission/ownership check failed\n";
            exit 1;
        }

        open(my $fh, '<', $filepath) or die "Cannot read: $!\n";
        local $/;
        my $code = <$fh>;
        close($fh);

        unless (validate_plugin_code($code, $plugin_name)) {
            print "FAIL: Code contains forbidden operations\n";
            exit 1;
        }

        print "OK: Plugin $plugin_name passed all validation checks\n";
    }
    else {
        print "Unknown command or missing arguments. Run without arguments for usage.\n";
        exit 1;
    }
}

